const json = $input.item.json;
const f = json.fields || json.Felder || {};

const thema   = f.field_1  || f.Field_1  || '(kein Thema)';
const caption = f.field_10 || f.Field_10 || '';
const bildUrl = String(f.field_8 || f.Field_8 || '').trim();
const itemId  = parseInt(String(json.AUSWEIS || json.id || 0).trim(), 10);

// Bild vorhanden wenn: nicht leer, nicht '0', nicht numerisch 0
const hatBild = bildUrl && bildUrl !== '0' && !/^0+$/.test(bildUrl) && bildUrl.startsWith('http');

return {
  json: {
    ...json,
    thema:              thema,
    caption:            caption,
    bild_url:           hatBild ? bildUrl : '',
    hat_bild:           hatBild,
    sharepoint_item_id: itemId,
  }
};

// PFAD B: Manuelles Bild direkt verwenden
const json = $input.item.json;
return {
  json: {
    final_bild_url:      json.bild_url,
    thema:               json.thema,
    sharepoint_item_id:  json.sharepoint_item_id,
    bild_quelle:         'manuell',
    generated_at:        new Date().toISOString()
  }
};

// PFAD A: HTML-Template für Physio Fuchs generieren
const json = $input.item.json;
const thema = json.thema || 'Physiotherapie';

const gruen     = '#5a7a4a';
const hellgruen = '#6e9b5e';
const creme     = '#f2ede4';
const weiss     = '#ffffff';

const html = `
<div style="
  width:1080px;
  height:1920px;
  background:${creme};
  font-family:'Georgia',serif;
  position:relative;
  overflow:hidden;
  display:flex;
  flex-direction:column;
  align-items:center;
  justify-content:center;
">
  <div style="position:absolute;top:0;left:0;right:0;height:90px;background:${gruen};"></div>
  <div style="position:absolute;top:30px;right:60px;width:280px;height:220px;opacity:0.25;background:${hellgruen};border-radius:50% 0 50% 0;transform:rotate(20deg);"></div>
  <div style="position:absolute;top:60px;right:200px;width:180px;height:140px;opacity:0.15;background:${hellgruen};border-radius:50% 0 50% 0;transform:rotate(20deg);"></div>
  <div style="background:${gruen};padding:55px 70px;text-align:center;width:920px;margin-bottom:220px;position:relative;z-index:2;">
    <div style="position:absolute;top:-20px;right:20px;width:120px;height:100px;opacity:0.3;background:${hellgruen};border-radius:50% 0 50% 0;transform:rotate(15deg);"></div>
    <div style="color:${weiss};font-size:${thema.length > 20 ? '68px' : '82px'};font-weight:bold;line-height:1.2;letter-spacing:1px;position:relative;z-index:3;">${thema}</div>
  </div>
  <div style="position:absolute;bottom:200px;left:40px;width:200px;height:160px;opacity:0.2;background:${gruen};border-radius:50% 0 50% 0;transform:rotate(200deg);"></div>
  <div style="position:absolute;bottom:140px;left:50%;transform:translateX(-50%);background:${weiss};padding:28px 70px;border-radius:4px;text-align:center;box-shadow:0 4px 20px rgba(0,0,0,0.12);white-space:nowrap;">
    <div style="font-size:38px;letter-spacing:10px;color:${gruen};font-weight:bold;font-family:'Georgia',serif;">PHYSIO FUCHS</div>
  </div>
  <div style="position:absolute;bottom:0;left:0;right:0;height:90px;background:${gruen};"></div>
  <div style="position:absolute;bottom:50px;right:80px;width:160px;height:120px;opacity:0.25;background:${hellgruen};border-radius:50% 0 50% 0;transform:rotate(20deg);"></div>
</div>
`;

return {
  json: {
    html: html,
    viewport_width: 1080,
    viewport_height: 1920,
    _meta: {
      thema: thema,
      sharepoint_item_id: json.sharepoint_item_id
    }
  }
};

const response = $input.item.json;
const prev = $('HTML Template generieren').item.json._meta;

const imageUrl = response.url || response.image_url || '';

if (!imageUrl) {
  throw new Error('Kein Bild-URL von hcti.io. Response: ' + JSON.stringify(response).substring(0, 300));
}

return {
  json: {
    final_bild_url:     imageUrl,
    thema:              prev?.thema || '',
    sharepoint_item_id: prev?.sharepoint_item_id || 0,
    bild_quelle:        'html',
    generated_at:       new Date().toISOString()
  }
};
